                                            <tr className="bg-purple-50">
                                                <td className="border border-gray-300 p-3">Bayram / Sosyal Harcamalar</td>
                                                <td className="border border-gray-300 p-3">8%</td>
                                                <td className="border border-gray-300 p-3">15.000</td>
                                                <td className="border border-gray-300 p-3">Özel Bankalar (%60)</td>
                                            </tr>
